INSERT INTO `dHFxxem_events` (`event_id`, `post_id`, `event_slug`, `event_owner`, `event_status`, `event_name`, `event_start_time`, `event_end_time`, `event_all_day`, `event_start_date`, `event_end_date`, `post_content`, `event_rsvp`, `event_rsvp_date`, `event_rsvp_time`, `event_rsvp_spaces`, `event_spaces`, `event_private`, `location_id`, `recurrence_id`, `event_date_created`, `event_date_modified`, `recurrence`, `recurrence_interval`, `recurrence_freq`, `recurrence_byday`, `recurrence_byweekno`, `recurrence_days`, `recurrence_rsvp_days`, `blog_id`, `group_id`, `event_start`, `event_end`, `event_timezone`) VALUES
(3, 857, 'les-shadoks-ont-50-ans-une-revolution-animee', 1, 1, 'Les Shadoks ont 50 ans : Une révolution animée', '10:00:00', '18:00:00', 0, '2018-04-05', '2018-07-18', 'En partenariat avec le Shadok, le Musée Tomi Ungerer – Centre international de l’Illustration propose de découvrir ou de redécouvrir la fameuse série télévisée les shadoks de films d’animation créée en 1968 par Jacques Rouxel.\r\nPour la première fois l’oeuvre du créateur est exposée dans un musée labellisé « Musée de France » avec l’objectif de l’inscrire dans l’histoire de l’illustration du XXe siècle.', 1, '2018-07-18', '10:00:00', 0, 0, 0, 4, NULL, '2018-04-03 16:28:10', '2018-04-04 14:52:09', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0, '2018-04-05 10:00:00', '2018-07-18 18:00:00', 'UTC'),
(4, 877, 'educap-city', 1, 1, 'EDUCAP CITY', '10:30:00', '17:30:00', 0, '2018-04-05', '2018-04-05', 'Parcours d’orientation educap city en milieu urbain encadré par le Centre de Loisirs Jeunes de la police Nationale afin de faire découvrir l''Histoire de leur ville aux enfants et les sensibiliser sur le civisme, le respect, les discriminations, ainsi que le fonctionnement et le rôle de l''institution.', 1, '2018-04-05', '16:30:00', 0, 0, 0, 5, NULL, '2018-04-04 07:51:36', '2018-04-04 13:56:15', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0, '2018-04-05 10:30:00', '2018-04-05 17:30:00', 'UTC'),
(5, 879, 'kvelertak', 1, 1, 'Kvelertak', '20:30:00', '23:30:00', 0, '2018-04-10', '2018-04-10', 'Formé en 2007 KVELERTAK connaît une ascension rapide et incarne un des meilleurs représentants du metal des années 2010 : syncrétique, décomplexé et taillé pour le live.\r\nA l''image de Baroness, les Norvégiens ont ramené une grosse touche fun et heavy dans un univers dark, celui du black metal.\r\nLe groupe est en tournée avec Metallica.', 1, '2018-04-10', '20:30:00', 0, 0, 0, 6, NULL, '2018-04-04 08:13:46', '2018-04-04 14:55:51', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0, '2018-04-10 20:30:00', '2018-04-10 23:30:00', 'UTC'),
(2, 836, 'journees-europeennes-des-metiers-dart', 1, -1, 'Journées européennes des métiers d''art', '00:00:00', '23:59:59', 1, '2018-04-03', '2018-04-08', 'Les Journées Européennes des Métiers d''Art sont la plus grande manifestation internationale dédiée à la découverte des métiers d’art.', 1, '2018-04-08', '00:00:00', 0, 0, 0, 0, NULL, '2018-04-03 12:59:45', '2018-04-04 09:05:43', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0, '2018-04-02 22:00:00', '2018-04-08 21:59:59', 'Europe/Paris'),
(6, 883, 'conference-femmes-guerrieres-du-dahomey', 1, 1, 'Conférence : Femmes guerrières du Dahomey', '20:00:00', '23:00:00', 0, '2018-04-11', '2018-04-11', 'Les femmes guerrières du Dahomey ont servi le régime avec une abnégation sans faille.\r\nRedoutées par tous ceux qui les ont affrontées, elles ont marqué les esprits, non seulement au Dahomey mais dans toute l''Afrique.', 1, '2018-04-11', '20:00:00', 0, 0, 0, 7, NULL, '2018-04-04 08:25:32', '2018-04-04 14:57:04', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0, '2018-04-11 20:00:00', '2018-04-11 23:00:00', 'UTC'),
(7, 885, 'les-courses-de-strasbourg', 1, 1, 'Les courses de Strasbourg', '00:00:00', '23:59:59', 1, '2018-04-13', '2018-04-15', 'Véritable festival du sport pour tous en Alsace, les Courses de Strasbourg Europe rassemblent chaque année plus de 13 000 participants sur 6 épreuves, faisant ainsi de ce rendez-vous la plus grande course de la Région Grand Est et l’une des plus importantes de France.', 1, '2018-04-13', '00:00:00', 0, 0, 0, 8, NULL, '2018-04-04 08:33:03', '2018-04-04 15:00:07', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0, '2018-04-13 00:00:00', '2018-04-15 23:59:59', 'UTC'),
(8, 887, 'festival-humour-droles-de-zebres', 1, 1, 'Drôles de Zèbres', '20:00:00', '22:30:00', 0, '2018-04-13', '2018-04-20', 'Drôles de Zèbres est un festival d''humour à Strasbourg qui réunit de jeunes humoristes et des artistes confirmés de toutes les origines : France, Belgique, Suisse et Espagne. Créé en 2003, le festival propose chaque année des spectacles burlesques et drôles qui invitent le public à se détendre et à passer un bon moment.<a href="http://www.droles-de-zebres.com" target="_blank" rel="noopener"></a>', 1, '2018-04-13', '20:00:00', 0, 0, 0, 9, NULL, '2018-04-04 08:42:43', '2018-04-04 15:01:24', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0, '2018-04-13 20:00:00', '2018-04-20 22:30:00', 'UTC'),
(9, 889, 'marcus-miller', 1, 1, 'Marcus Miller', '20:00:00', '22:30:00', 0, '2018-04-18', '2018-04-18', 'Marcus Miller remonte sur scène à l’auditorium Erasme pour notre plus grand plaisir en 2018.\r\nIl revient avec un nouvel Opus (Blue Note/Universal) et comme chaque fois, Marcus Miller va tous nous surprendre. Nous avons hâte de le découvrir et de l''écouter en live…', 1, '2018-04-18', '20:00:00', 0, 0, 0, 10, NULL, '2018-04-04 09:02:30', '2018-04-04 09:33:44', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0, '2018-04-18 20:00:00', '2018-04-18 22:30:00', 'UTC'),
(10, 894, 'big-flo-et-oli', 1, 1, 'Big Flo et Oli', '20:00:00', '22:30:00', 0, '2018-04-20', '2018-04-20', 'Après une tournée à guichets fermés à l’automne 2017, les deux toulousains Big Flo et Oli partent à la conquête des Zéniths ! Une nouvelle tournée d’une dizaine de dates à travers la France, mais également en Belgique et en Suisse.', 1, '2018-04-20', '20:00:00', 0, 0, 0, 11, NULL, '2018-04-04 09:50:33', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0, '2018-04-20 20:00:00', '2018-04-20 22:30:00', 'UTC'),
(11, 896, 'alchimie-et-physique-quantique', 1, 1, 'Alchimie et Physique quantique', '15:00:00', '17:00:00', 0, '2018-04-21', '2018-04-21', 'L’alchimie nous invite, par ses livres et ses symboles, à découvrir les mystères de la Nature et de l’Homme. L’initiation hermétique, sous-jacente à toute démarche alchimique, nous ouvre les yeux et la conscience à des aspects inconnus et insoupçonnés de la matière et de nous-même.\r\nLe conférencier Jean-Claude Pascal vous propose de découvrir avec lui, ses fameux mystères, ce 21 avril à la Bibliothèque Pythagore de Strasbourg.', 1, '2018-04-21', '15:00:00', 0, 0, 0, 12, NULL, '2018-04-04 10:07:06', '2018-04-04 10:07:40', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0, '2018-04-21 15:00:00', '2018-04-21 17:00:00', 'UTC'),
(12, 898, 'salon-du-tissu-edition-printemps-ete', 1, 1, 'Salon du tissu Edition Printemps/Eté', '10:00:00', '17:00:00', 0, '2018-04-22', '2018-04-22', 'Sur plus de 4000 mètres carrés, vous trouverez :\r\ntissu pour la conception de vêtements, pour robe de mariée, pour la haute couture, pour enfants, pour le patchwork ou la décoration, d''ameublement mais aussi du cuir, des toiles cirées, et tout le nécessaire de mercerie.', 1, '2018-04-22', '10:00:00', 0, 0, 0, 13, NULL, '2018-04-04 10:15:30', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0, '2018-04-22 10:00:00', '2018-04-22 17:00:00', 'UTC'),
(13, 900, 'stage-kayak-escalade-a-lascpa', 1, 1, 'Stage kayak/escalade à l’ASCPA', '00:00:00', '23:59:59', 1, '2018-04-23', '2018-04-27', 'L’ASCPA organise un stage kayak/escalade de 5 jours pour les jeunes de 7 à 17 ans durant les vacances de Printemps 2018.', 1, '2018-04-23', '00:00:00', 0, 0, 0, 14, NULL, '2018-04-04 10:22:23', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0, '2018-04-23 00:00:00', '2018-04-27 23:59:59', 'UTC'),
(14, 902, 'revolution-cubaine-soiree-salsa', 1, 1, 'Révolution Cubaine soirée Salsa', '21:00:00', '06:00:00', 0, '2018-04-27', '2018-04-28', 'Une soirée Salsa dans la peau d''un révolutionnaire ?\r\nVotre rêve le plus fou va enfin devenir réalité !\r\nDevenez un révolutionnaire dans le maquis, cigare aux lèvres\r\nAprès la soirée Carnaval, rien de mieux que la rigueur de la lutte révolutionnaire pour imposer la Salsa partout dans le monde.', 1, '2018-04-27', '21:00:00', 0, 0, 0, 15, NULL, '2018-04-04 12:04:47', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0, '2018-04-27 21:00:00', '2018-04-28 06:00:00', 'UTC'),
(15, 908, 'lord-esperanza', 1, 1, 'Lord Esperanza', '20:00:00', '22:00:00', 0, '2018-04-05', '2018-04-05', 'Une nouvelle étoile filante du rap français, Lord Esperanza se démarque par la finesse de sa plume et la vélocité son propos.\r\nPar amour de l’écriture, il gratte ses premiers textes au collège et se proclame Lord Esperanza en hommage au roman de Michel Tournier ’Vendredi ou la vie sauvage’.', 1, '2018-04-05', '20:00:00', 0, 0, 0, 16, NULL, '2018-04-04 13:14:00', '2018-04-04 14:53:21', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0, '2018-04-05 20:00:00', '2018-04-05 22:00:00', 'UTC');
