(1036, 'dbem_event_resubmitted_email_subject', 'Évènement resoumis en attente d’approbation', 'yes'),
(1037, 'dbem_event_resubmitted_email_body', 'Un évènement déjà publié vient d’être modifié par #_CONTACTNAME. et cet évènement n’est plus en ligne, il attend votre validation.\r\n\r\n Nom : #_EVENTNAME \r\n\r\nDate : #_EVENTDATES \r\n\r\nHeure : #_EVENTTIMES \r\n\r\nVeuillez visiter la page http://strasbourg.sandrine-alcazar.com/wp-admin/post.php?action=edit&post=#_EVENTPOSTID pour valider cet évènement.\r\n\r\n\r\n-------------------------------\r\n', 'yes'),
(1038, 'dbem_event_published_email_subject', 'Soumettre - #_EVENTNAME', 'yes'),
(1039, 'dbem_event_published_email_body', 'Un nouvel évènement vient d’être publié par #_CONTACTNAME.\r\n\r\nNom : #_EVENTNAME \r\n\r\nDate : #_EVENTDATES \r\n\r\nHeure : #_EVENTTIMES \r\n\r\nModifier cet évènement - http://strasbourg.sandrine-alcazar.com/wp-admin/post.php?action=edit&post=#_EVENTPOSTID\r\n\r\nVoir cet évènement - #_EVENTURL\r\n\r\n\r\n-------------------------------\r\n\r\n', 'yes'),
(1040, 'dbem_event_approved_email_subject', 'Évènement approuvé - #_EVENTNAME', 'yes'),
(1041, 'dbem_event_approved_email_body', 'Cher/chère #_CONTACTNAME, \r\n\r\nVotre évènement #_EVENTNAME le #_EVENTDATES a été approuvé.\r\n\r\nVous pouvez visualiser votre évènement ici : #_EVENTURL\r\n\r\n\r\n-------------------------------\r\n', 'yes'),
