(1237, 'dbem_bookings_contact_email_rejected_body', 'La réservation suivante est rejetée :\r\n\r\n#_EVENTNAME - #_EVENTDATES @ #_EVENTTIMES\r\n\r\nMaintenant il y a #_BOOKEDSPACES places réservées et #_AVAILABLESPACES places sont encore disponibles.\r\n\r\nDétails de la réservation :\r\n\r\nNom : #_BOOKINGNAME\r\nE-mail : #_BOOKINGEMAIL\r\n\r\n#_BOOKINGSUMMARY\r\n\r\n', 'yes'),
(1238, 'dbem_bookings_contact_email_cancelled_subject', 'Réservation annulée', 'yes'),
(1239, 'dbem_bookings_contact_email_cancelled_body', 'La réservation suivante est annulée :\r\n\r\n#_EVENTNAME - #_EVENTDATES @ #_EVENTTIMES\r\n\r\nMaintenant il y a #_BOOKEDSPACES places réservées et #_AVAILABLESPACES places sont encore disponibles.\r\n\r\nDétails de la réservation :\r\n\r\nNom : #_BOOKINGNAME\r\nE-mail : #_BOOKINGEMAIL\r\n\r\n#_BOOKINGSUMMARY\r\n', 'yes'),
(1240, 'dbem_bookings_email_pending_subject', 'Réservation en attente', 'yes'),
(1241, 'dbem_bookings_email_pending_body', 'Cher/chère #_BOOKINGNAME,\r\n\r\nVous avez demandé à réserver #_BOOKINGSPACES place(s) pour #_EVENTNAME.\r\n\r\nQuand : #_EVENTDATES à #_EVENTTIMES\r\n\r\nOù : #_LOCATIONNAME - #_LOCATIONFULLLINE\r\n\r\nCette réservation est maintenant en attente d’approbation par nos administrateurs : une fois approuvée vous recevrez un e-mail automatique de confirmation.\r\n\r\nCordialement,\r\n\r\n#_CONTACTNAME\r\n\r\n\r\n-------------------------------\r\n', 'yes'),
(1242, 'dbem_bookings_email_rejected_subject', 'Réservation rejetée', 'yes'),
(1243, 'dbem_bookings_email_rejected_body', 'Cher/chère #_BOOKINGNAME,\r\n\r\n\r\nVotre réservation pour#_BOOKINGSPACES place(s) pour #_EVENTNAME le #_EVENTDATES a été rejetée. \r\n\r\nCordialement,\r\n\r\n#_CONTACTNAME\r\n\r\n\r\n-------------------------------\r\n', 'yes'),
(1244, 'dbem_bookings_email_confirmed_subject', 'Réservation confirmée', 'yes'),
(1245, 'dbem_bookings_email_confirmed_body', 'Cher/chère #_BOOKINGNAME,\r\n\r\nVous avez réservé #_BOOKINGSPACES place(s) pour #_EVENTNAME.\r\n\r\nQuand : #_EVENTDATES à #_EVENTTIMES\r\n\r\nOù : #_LOCATIONNAME - #_LOCATIONFULLLINE\r\n\r\nCordialement,\r\n\r\n#_CONTACTNAME\r\n\r\n\r\n-------------------------------\r\n', 'yes'),
(1246, 'dbem_bookings_email_cancelled_subject', 'Réservation annulée', 'yes'),
(1247, 'dbem_bookings_email_cancelled_body', 'Cher/chère #_BOOKINGNAME,\r\n\r\nVotre réservation de #_BOOKINGSPACES place(s) pour #_EVENTNAME le #_EVENTDATES a été annulée.\r\n\r\nCordialement,\r\n\r\n#_CONTACTNAME\r\n\r\n\r\n-------------------------------\r\n', 'yes'),
(1248, 'dbem_bookings_email_registration_subject', '[Office de Tourisme de Strasbourg] Votre nom d’utilisateur et mot de passe', 'yes'),
(1249, 'dbem_bookings_email_registration_body', 'Vous avez créé un compte sur l''Office de Tourisme de Strasbourg.\r\n\r\nVous pouvez vous connecter sur notre site ici : http://strasbourg.sandrine-alcazar.com/wp-login.php\r\n\r\nNom d’utilisateur : : %username%\r\n\r\nMot de passe : %password%\r\n\r\nPour voir vos réservations, merci de vous rendre ici http://strasbourg.sandrine-alcazar.com/evenement/mes-reservations après vous êtes connectés au site.', 'yes'),
