xt-align: center;\\">ACTUALIT\\u00c9S<\\/h4><p>Vous pouvez retrouver dans cette page toutes les news en temps r\\u00e9el afin d''\\u00eatre inform\\u00e9 de tout ce qui se passe \\u00e0 Strasbourg.<\\/p>","align":"center","text_color":"#54595f","typography_typography":"custom","typography_font_family":"Aref Ruqaa"},"elements":[],"widgetType":"text-editor"}],"isInner":false},{"id":"98f8fb5","elType":"column","settings":{"_column_size":25,"_inline_size":null,"background_hover_background":"classic","background_hover_color":"#f6f0e5","background_hover_color_b":"#e1c1a1"},"elements":[{"id":"bce2d2e","elType":"widget","settings":{"icon":"fa fa-info-circle","link":{"url":"http:\\/\\/strasbourg.sandrine-alcazar.com\\/plus-dinfos","is_external":"","nofollow":""},"primary_color":"#4054b2","hover_primary_color":"#d10202","hover_animation":"grow"},"elements":[],"widgetType":"icon"},{"id":"6d0d3f6","elType":"widget","settings":{"editor":"<h4 style=\\"font-size: 20px; text-align: center;\\">PLUS<i> <\\/i>D''INFOS<\\/h4><p>Cette page, elle, vous conseille quelques activit\\u00e9s pour vous donner des id\\u00e9es lors de vos prochaines excursions dans la ville.<\\/p>","align":"center","typography_typography":"custom","typography_font_family":"Aref Ruqaa"},"elements":[],"widgetType":"text-editor"}],"isInner":false},{"id":"feb67b9","elType":"column","settings":{"_column_size":25,"_inline_size":null,"background_hover_background":"classic","background_hover_color":"#f6f0e5","background_hover_color_b":"#e1c1a1"},"elements":[{"id":"0695dae","elType":"widget","settings":{"icon":"fa fa-bicycle","link":{"url":"http:\\/\\/strasbourg.sandrine-alcazar.com\\/activites-du-mois","is_external":"","nofollow":""},"primary_color":"#d10202","hover_primary_color":"#23a455","hover_animation":"grow"},"elements":[],"widgetType":"icon"},{"id":"6b29b49","elType":"widget","settings":{"editor":"<h4 style=\\"font-size: 20px; text-align: center;\\">ACTIVITES DU MOIS<\\/h4><p>Dans celle-ci, nous avons list\\u00e9 pour vous tous les \\u00e9v\\u00e8nements du mois de fa\\u00e7on \\u00e0 ce que vous puissiez pr\\u00e9voir \\u00e0 l''avance vos sorties.<\\/p>","align":"center","typography_typography":"custom","typography_font_family":"Aref Ruqaa"},"elements":[],"widgetType":"text-editor"}],"isInner":false},{"id":"bed4f1a","elType":"column","settings":{"_column_size":25,"_inline_size":null,"background_hover_background":"classic","background_hover_color":"#f6f0e5","background_hover_color_b":"#e1c1a1"},"elements":[{"id":"d66de86","elType":"widget","settings":{"icon":"fa fa-phone","link":{"url":"http:\\/\\/strasbourg.sandrine-alcazar.com\\/contact","is_external":"","nofollow":""},"primary_color":"#23a455","hover_primary_color":"#e91e63","hover_animation":"grow"},"elements":[],"widgetType":"icon"},{"id":"cc4a8f5","elType":"widget","settings":{"editor":"<h4 style=\\"font-size: 20px; text-align: center;\\">CONTACT<\\/h4><div>Et si vous avez quand m\\u00eame besoin de plus d''informations, vous pouvez remplir le formulaire se trouvant sur cette page, nous vous r\\u00e9pondrons dans les meilleurs d\\u00e9lais.<\\/div><div><\\/div><div><\\/div><div><\\/div>","align":"center","typography_typography":"custom","typography_font_family":"Aref Ruqaa"},"elements":[],"widgetType":"text-editor"}],"isInner":false}],"isInner":false},{"id":"fab7a8a","elType":"section","settings":{"background_background":"classic","background_hover_color":"#f6f0e5","background_hover_color_b":"#e1c1a1","animation":"fadeInUp"},"elements":[{"id":"40781d8","elType":"column","settings":{"_column_size":100},"elements":[{"id":"7adcad0","elType":"widget","settings":{"title":"Strasbourg...","align":"left","title_color":"#e1c1a1","typography_typography":"custom","typography_font_family":"Merienda One","_margin":{"unit":"px","top":"66","right":"66","bottom":"66","left":"66","isLinked":true},"_margin_mobile":{"unit":"px","top":"38","right":"38","bottom":"38","left":"38","isLinked":true}},"elements":[],"widgetType":"heading"},{"id":"1ef318d","elType":"widget","settings":{"editor":"<p style=\\"text-align: left; font-family: Aref Ruqaa; padding-left: 30px;\\">\\u00c0 partir de 496, les Francs, ma\\u00eetres de l\\u2019Alsace, font surgir une nouvelle ville, Strateburgum (\\u00ab\\u00a0ville forte des routes\\u00a0\\u00bb).<\\/p><p style=\\"text-align: left; font-family: Aref Ruqaa; padding-left: 30px;\\">Fort modeste au d\\u00e9part, le bourg s\\u2019affirme sous le r\\u00e8gne des Carolingiens comme le carrefour des civilisations rh\\u00e9nanes.<\\/p><p style=\\"text-align: left; font-family: Aref Ruqaa; padding-left: 30px;\\">Strasbourg fut l\\u2019une des premi\\u00e8res villes \\u00e0 se d\\u00e9barrasser de la tutelle des \\u00e9v\\u00eaques, la bourgeoisie commer\\u00e7ante s\\u2019affirmant comme le vrai pouvoir.<br \\/> La construction de la cath\\u00e9drale ira de pair avec une prosp\\u00e9rit\\u00e9 grandissante.<br \\/> Le dynamisme \\u00e9conomique de la ville se double d''un bouillonnement intellectuel et culturel.<\\/p><p style=\\"text-align: left; font-family: Aref Ruqaa; padding-left: 30px;\\">Strasbourg, capitale de l\\u2019Europe et de l\\u2019Alsace, poss\\u00e8de un patrimoine historique et architectural qui en fait la ville la plus riche d\\u2019Alsace.<br \\/> Son centre ville fait partie du patrimoine mondial de L\\u2019UNESCO et ses mus\\u00e9es sont particuli\\u00e8rement riches et int\\u00e9ressants.<\\/p><p style=\\"text-align: left; font-family: Aref Ruqaa; padding-left: 30px;\\">L\\u2019histoire de la ville de Strasbourg est indissociable de l\\u2019histoire d\\u2019Alsace et, plus largement de la vall\\u00e9e du Rhin.<br \\/> Elle s\\u2019inscrit \\u00e9galement dans l\\u2019histoire de l\\u2019Europe, entre France et Allemagne, royaumes, empires ou r\\u00e9publiques.<\\/p>"},"elements":[],"widgetType":"text-editor"}],"isInner":false}],"isInner":false},{"id":"9b97d5f","elType":"section","settings":[],"elements":[{"id":"84165ca","elType":"column","settings":{"_column_size":100},"elements":[{"id":"d048664","elType":"widget","settings":[],"elements":[],"widgetType":"spacer"}],"isInner":false}],"isInner":false},{"id":"bec67fd","elType":"section","settings":{"content_width":{"unit":"px","size":892},"background_background":"classic","structure":"22","background_hover_background":"classic","background_hover_color_b":"#e1c1a1","background_hover_transition":{"unit":"px","size":0.6},"shape_divider_bottom_color":"#f6f0e5","shape_divider_bottom_height":{"unit":"px","size":60},"animation":"fadeInUp"},"elements":[{"id":"a076978","elType":"column","settings":{"_column_size":66,"content_position":"center","background_background":"classic","_inline_size":null,"background_hover_background":"classic","background_hover_color":"#f6f0e5"},"elements":[{"id":"e16a0b7","elType":"widget","settings":{"wp":{"title":"A LA UNE","number":"1","show_date":"on"},"_margin":{"unit":"px","top":"0","right":"0","bottom":"0","left":"0","isLinked":true},"_padding":{"unit":"px","top":"28","right":"28","bottom":"28","left":"28","isLinked":true},"_element_id":"recent_post","_background_hover_background":"gradient","_border_color":"#ffffff","_background_image":{"url":"http:\\/\\/strasbourg.sandrine-alcazar.com\\/wp-content\\/uploads\\/2018\\/03\\/830x532_led-horticoles-permettent-jeunes-poussent-grandir-tunnel-bunker-comestible-strasbourg-1.jpg","id":459},"_background_position":"center center","_background_repeat":"no-repeat","_background_size":"cover"},"elements":[],"widgetType":"wp-widget-recent-posts"}],"isInner":false},{"id":"bf06831","elType":"column","settings":{"_column_size":66,"_inline_size":null,"content_position":"center","background_hover_background":"classic","background_hover_color":"#f6f0e5"},"elements":[{"id":"f0ce197","elType":"widget","settings":{"image":{"url":"http:\\/\\/strasbourg.sandrine-alcazar.com\\/wp-content\\/uploads\\/2018\\/03\\/830x532_led-horticoles-permettent-jeunes-poussent-grandir-tunnel-bunker-comestible-strasbourg.jpg","id":457},"