(1653, 88, '_elementor_data', '[{"id":"ed44572","elType":"section","settings":[],"elements":[{"id":"54f1f62","elType":"column","settings":{"_column_size":100},"elements":[{"id":"82c22b6","elType":"widget","settings":{"editor":"<h2>Avril 2018<\\/h2><p>Trouvez ici une liste de toutes les activit\\u00e9s du mois en cours de la r\\u00e9gion alsacienne.<br \\/> Vous pouvez y participer gr\\u00e2ce au bouton inscription se trouvant \\u00e0 c\\u00f4t\\u00e9 de chacune d\\u2019entre elles.<\\/p>"},"elements":[],"widgetType":"text-editor"}],"isInner":false}],"isInner":false},{"id":"2468807","elType":"section","settings":[],"elements":[{"id":"f773dba","elType":"column","settings":{"_column_size":100},"elements":[{"id":"26f592c","elType":"widget","settings":{"wp":{"title":"\\u00c9v\\u00e8nements","limit":"5","scope":"all","orderby":"event_start_date,event_start_time,event_name","order":"ASC","category":"0","all_events_text":"tous les \\u00e9v\\u00e8nements","format":"<li>#_EVENTLINK<ul><li>#_EVENTDATES<\\/li><li>#_LOCATIONTOWN<\\/li><\\/ul><\\/li>","no_events_text":"<li>Aucun \\u00e9v\\u00e8nement<\\/li>"}},"elements":[],"widgetType":"wp-widget-em_widget"}],"isInner":false}],"isInner":false}]'),
