(2188, 446, '_elementor_data', '[{"id":"7a3b54f","elType":"section","settings":{"structure":"22","background_hover_background":"classic","background_hover_color":"#f6f0e5","animation":"fadeInLeft"},"elements":[{"id":"7e51c85","elType":"column","settings":{"_column_size":66,"_inline_size":null,"content_position":"center","background_hover_background":"classic","background_hover_color":"#f6f0e5","background_hover_transition":{"unit":"px","size":1}},"elements":[{"id":"f32c308","elType":"widget","settings":{"editor":"<h4 style=\\"text-align: center;\\"><span style=\\"font-size: 20px; color: #000000;\\"><strong>La Maison Kammerzell<\\/strong><\\/span><\\/h4>\\n\\n<p style=\\"font-family:Aref Ruqaa;\\">Id\\u00e9alement situ\\u00e9 au pied de la Cath\\u00e9drale de Strasbourg, au c\\u0153ur de l\\u2019Europe, la c\\u00e9l\\u00e8bre Maison Kammerzell est un lieu incontournable \\u00e0 visiter.\\n\\nConsid\\u00e9r\\u00e9e comme \\u00ab la plus belle maison de Strasbourg \\u00bb, elle symbolise des splendeurs s\\u00e9culaires de la ville qui en tire une grande fiert\\u00e9.\\n\\nElle est l\\u2019une des plus belles brasseries du monde et vous propose ce dimanche 15 avril \\u00e0 9h45 une visite guid\\u00e9e afin de d\\u00e9couvrir tous les d\\u00e9tails de sa construction et son histoire.<\\/p>","drop_cap":"yes","align_mobile":"justify","text_color":"#54595f","typography_typography":"custom","typography_font_size":{"unit":"px","size":14},"_background_hover_background":"classic"},"elements":[],"widgetType":"text-editor"}],"isInner":false},{"id":"a2353de","elType":"column","settings":{"_column_size":33,"_inline_size":null,"content_position":"center"},"elements":[{"id":"caae1de","elType":"widget","settings":{"image":{"url":"http:\\/\\/strasbourg.sandrine-alcazar.com\\/wp-content\\/uploads\\/2018\\/03\\/4864510031_768bc2605d-e1521545781809.jpg","id":238},"image_size":"full","align_tablet":"center","link_to":"custom","link":{"url":"https:\\/\\/www.maison-kammerzell.com\\/","is_ext