xt-align: center;\\">ACTUALIT\\u00c9S<\\/h4><p>Vous pouvez retrouver dans cette page toutes les news en temps r\\u00e9el afin d''\\u00eatre inform\\u00e9 de tout ce qui se passe \\u00e0 Strasbourg.<\\/p>","align":"center","text_color":"#54595f","typography_typography":"custom","typography_font_family":"Aref Ruqaa"},"elements":[],"widgetType":"text-editor"}],"isInner":false},{"id":"98f8fb5","elType":"column","settings":{"_column_size":25,"_inline_size":null,"background_hover_background":"classic","background_hover_color":"#f6f0e5","background_hover_color_b":"#e1c1a1"},"elements":[{"id":"bce2d2e","elType":"widget","settings":{"icon":"fa fa-info-circle","link":{"url":"http:\\/\\/strasbourg.sandrine-alcazar.com\\/plus-dinfos","is_external":"","nofollow":""},"primary_color":"#4054b2","hover_primary_color":"#d10202","hover_animation":"grow"},"elements":[],"widgetType":"icon"},{"id":"6d0d3f6","elType":"widget","settings":{"editor":"<h4 style=\\"font-size: 20px; text-align: center;\\">PLUS<i> <\\/i>D''INFOS<\\/h4><p>Cette page, elle, vous conseille quelques activit\\u00e9s pour vous donner des id\\u00e9es lors de vos prochaines excursions dans la ville.<\\/p>","align":"center","typography_typography":"custom","typography_font_family":"Aref Ruqaa"},"elements":[],"widgetType":"text-editor"}],"isInner":false},{"id":"feb67b9","elType":"column","settings":{"_column_size":25,"_inline_size":null,"background_hover_background":"classic","background_hover_color":"#f6f0e5","background_hover_color_b":"#e1c1a1"},"elements":[{"id":"0695dae","elType":"widget","settings":{"icon":"fa fa-bicycle","link":{"url":"http:\\/\\/strasbourg.sandrine-alcazar.com\\/activites-du-mois","is_external":"","nofollow":""},"primary_color":"#d10202","hover_primary_color":"#23a455","hover_animation":"grow"},"elements":[],"widgetType":"icon"},{"id":"6b29b49","elType":"widget","settings":{"editor":"<h4 style=\\"font-size: 20px; text-align: center;\\">ACTIVITES DU MOIS<\\/h4><p>Dans celle-ci, nous avons list\\u00e9 pour vous tous les \\u00e9v\\u00e8nements du mois de fa\\u00e7on \\u00e0 ce que vous puissiez pr\\u00e9voir \\u00e0 l''avance vos sorties.<\\/p>","align":"center","typography_typography":"custom","typography_font_family":"Aref Ruqaa"},"elements":[],"widgetType":"text-editor"}],"isInner":false},{"id":"bed4f1a","elType":"column","settings":{"_column_size":25,"_inline_size":null,"background_hover_background":"classic","background_hover_color":"#f6f0e5","background_hover_color_b":"#e1c1a1"},"elements":[{"id":"d66de86","elType":"widget","settings":{"icon":"fa fa-phone","link":{"url":"http:\\/\\/strasbourg.sandrine-alcazar.com\\/contact","is_external":"","nofollow":""},"primary_color":"#23a455","hover_primary_color":"#e91e63","hover_animation":"grow"},"elements":[],"widgetType":"icon"},{"id":"cc4a8f5","elType":"widget","settings":{"editor":"<h4 style=\\"font-size: 20px; text-align: center;\\">CONTACT<\\/h4><div>Et si vous avez quand m\\u00eame besoin de plus d''informations, vous pouvez remplir le formulaire se trouvant sur cette page, nous vous r\\u00e9pondrons dans les meilleurs d\\u00e9lais.<\\/div><div><\\/div><div><\\/div><div><\\/div>","align":"center","typography_typography":"custom","typography_font_family":"Aref Ruqaa"},"elements":[],"widgetType":"text-editor"}],"isInner":false}],"isInner":false},{"id":"279c9fe","elType":"section","settings":[],"elements":[{"id":"8b978ec","elType":"column","settings":{"_column_size":100},"elements":[{"id":"77fc8d1","elType":"widget","settings":[],"elements":[],"widgetType":"spacer"}],"isInner":false}],"isInner":false},{"id":"fab7a8a","elType":"section","settings":{"background_background":"classic","background_hover_color":"#f6f0e5","background_hover_color_b":"#e1c1a1","animation":"fadeInUp","content_width":{"unit":"px","size":767},"gap":"no","content_position":"middle","background_image":{"url":"http:\\/\\/strasbourg.sandrine-alcazar.com\\/wp-content\\/uploads\\/2018\\/03\\/Fond_histoire.jpg","id":542},"background_position":"center center","background_attachment":"scroll","background_repeat":"no-repeat","background_size":"cover"},"elements":[{"id":"40781d8","elType":"column","settings":{"_column_size":100,"_inline_size_tablet":100,"content_position":"center"},"elements":[{"id":"68139f8","elType":"widget","settings":[],"elements":[],"widgetType":"spacer"},{"id":"7adcad0","elType":"widget","settings":{"title":"Strasbourg...","align":"left","title_color":"#e1c1a1","typography_typography":"custom","typography_font_family":"Merienda One","_margin":{"unit":"px","top":"0","right":"0","bottom":"0","left":"0","isLinked":true},"_margin_mobile":{"unit":"px","top":"38","right":"38","bottom":"38","left":"38","isLinked":true}},"elements":[],"widgetType":"heading"},{"id":"1ef318d","elType":"widget","settings":{"editor":"<p style=\\"text-align: left; font-family: Aref Ruqaa;\\"><span style=\\"color: #ffffff;\\">\\u00c0 partir de 496, les Francs, ma\\u00eetres de l\\u2019Alsace, font surgir une nouvelle ville, Strateburgum (\\u00ab\\u00a0ville forte des routes\\u00a0\\u00bb).<\\/span><\\/p><p style=\\"text-align: left; font-family: Aref Ruqaa;\\"><span style=\\"color: #ffffff;\\">Fort modeste au d\\u00e9part, le bourg s\\u2019affirme sous le r\\u00e8gne des Carolingiens comme le carrefour des civilisations rh\\u00e9nanes.<\\/span><\\/p><p style=\\"text-align: left; font-family: Aref Ruqaa;\\"><span style=\\"color: #ffffff;\\">Strasbourg fut l\\u2019une des premi\\u00e8res villes \\u00e0 se d\\u00e9barrasser de la tutelle des \\u00e9v\\u00eaques, la bourgeoisie commer\\u00e7ante s\\u2019affirmant comme le vrai pouvoir.<\\/span><br \\/><span style=\\"color: #ffffff;\\"> La construction de la cath\\u00e9drale ira de pair avec une prosp\\u00e9rit\\u00e9 grandissante.<\\/span><br \\/><span style=\\"color: #ffffff;\\"> Le dynamisme \\u00e9conomique de la ville se double d''un bouillonnement intellectuel et culturel.<\\/span><\\/p><p style=\\"text-align: left; font-family: Aref Ruqaa;\\"><span style=\\"color: #ffffff;\\">Strasbourg, capitale de l\\u2019Europe et de l\\u2019Alsace, poss\\u00e8de un patrimoine historique et architectural qui en fait la ville la plus riche d\\u2019Alsace.<\\/span><br \\/><span style=\\"color: #ffffff;\\"> Son centre ville fait partie du patrimoine mondial de L\\u2019UNESCO et ses mus\\u00e9es sont particuli\\u00e8rement riches et int\\u00e9ressants.<\\/span><\\/p><p style=\\"text-align: left; font-family: Aref Ruqaa;\\"><span style=\\"color: #ffffff;\\">L\\u2019histoire de la ville de Strasbourg est indissociable de l\\u2019histoire d\\u2019Alsace et, plus largement de la vall\\u00e9e du Rhin.<\\/span><br \\/><span style=\\"color: #ffffff;\\"> Elle s\\u2019inscrit \\u00e9galement dans l\\u2019histoire de l\\u2019Europe, entre France et Allemagne, royaumes, empires ou r\\u00e9publiques.<\\/span><\\/p>"},"elements":[],"widgetType":"text-editor"},{"id":"359a72a","elType":"widget","settings":[],"elements":[],"widgetType":"spacer"}],"isInner":false}],"isInner":false},{"id":"9b97d5f","elType":"section","settings":[],"elements":[{"id":"84165ca","elType":"column","settings":{"_column_size":100},"elements":[{"id":"d048664","elType":"widget","settings":[],"elements":[],"widgetType":"spacer"}],"isInner":false}],"isInner":false},{"id":"c151ec5","elType":"section","settings":{"background_hover_background":"classic","animation":"fadeInUp"},"elements":[{"id":"bdb9732","elType":"column","settings":{"_column_size":100,"background_hover_background":"classic"},"elements":[{"id":"ee5fd04","elType":"widget","settings":{"wp":{"title":"A LA UNE","number_posts":"1","post_title_length":"1000","show_author":"on","category_label":"In","show_date":"on","excerpt_length":"55","excerpt_more":" [\\u2026]","category_ids":["0"],"show_thumb":"on","thumb_dimensions":"medium","thumb_width":"75","thumb_height":"75","default_url":"http:\\/\\/strasbourg.sandrine-alcazar.com\\/wp-content\\/plugins\\/recent-posts-widget-with-thumbnails\\/default_thumb.gif"},"_background_hover_background":"classic","_background_hover_color":"#f6f0e5"},"elements":[],"widgetType":"wp-widget-recent-posts-widget-with-thumbnails"}],"isInner":false}],"isInner":false}]'),
