1a","elType":"column","settings":{"_column_size":25,"_inline_size":null,"background_hover_background":"classic","background_hover_color":"#f6f0e5"},"elements":[{"id":"d66de86","elType":"widget","settings":{"icon":"fa fa-phone","link":{"url":"http:\\/\\/strasbourg.sandrine-alcazar.com\\/contact","is_external":"","nofollow":""},"primary_color":"#d10202","_animation":"fadeInUp"},"elements":[],"widgetType":"icon"},{"id":"cc4a8f5","elType":"widget","settings":{"editor":"<h4 style=\\"font-size: 20px; text-align: center;\\">CONTACT<\\/h4><div>Et si vous avez quand m\\u00eame besoin de plus d''informations, vous pouvez remplir le formulaire se trouvant sur cette page, nous vous r\\u00e9pondrons dans les meilleurs d\\u00e9lais.<\\/div><div><\\/div><div><\\/div><div><\\/div>","align":"center","_animation":"fadeInUp","typography_typography":"custom","typography_font_family":"Aref Ruqaa"},"elements":[],"widgetType":"text-editor"}],"isInner":false}],"isInner":false},{"id":"821e8be","elType":"section","settings":{"content_width":{"unit":"px","size":892},"background_background":"classic"},"elements":[{"id":"67bdc25","elType":"column","settings":{"_column_size":100,"content_position":"center","animation":"fadeInUp","background_background":"classic"},"elements":[{"id":"1b621cc","elType":"widget","settings":[],"elements":[],"widgetType":"spacer"}],"isInner":false}],"isInner":false},{"id":"fab7a8a","elType":"section","settings":[],"elements":[{"id":"40781d8","elType":"column","settings":{"_column_size":100},"elements":[{"id":"7adcad0","elType":"widget","settings":{"title":"Strasbourg...","align":"center","title_color":"#54595f","typography_typography":"custom","typography_font_family":"Merienda One"},"elements":[],"widgetType":"heading"},{"id":"1ef318d","elType":"widget","settings":{"editor":"<p>\\u00c0 partir de 496, les Francs, ma\\u00eetres de l\\u2019Alsace, font surgir une nouvelle ville, Strateburgum (\\u00ab&nbsp;ville forte des routes&nbsp;\\u00bb). <\\/p>\\n<p>Fort modeste au d\\u00e9part, le bourg s\\u2019affirme sous le r\\u00e8gne des Carolingiens comme le carrefour des civilisations rh\\u00e9nanes.<\\/p>\\n<p>Strasbourg fut l\\u2019une des premi\\u00e8res villes \\u00e0 se d\\u00e9barrasser de la tutelle des \\u00e9v\\u00eaques, la bourgeoisie commer\\u00e7ante s\\u2019affirmant comme le vrai pouvoir. <br>La construction de la cath\\u00e9drale ira de pair avec une prosp\\u00e9rit\\u00e9 grandissante. <br>Le dynamisme \\u00e9conomique de la ville se double d''un bouillonnement intellectuel et culturel.<\\/p>\\n<p>Strasbourg, capitale de l\\u2019Europe et de l\\u2019Alsace, poss\\u00e8de un patrimoine historique et architectural qui en fait la ville la plus riche d\\u2019Alsace.<br>Son centre ville fait partie du patrimoine mondial de L\\u2019UNESCO et ses mus\\u00e9es sont particuli\\u00e8rement riches et int\\u00e9ressants.<\\/p>\\n<p>L\\u2019histoire de la ville de Strasbourg est indissociable de l\\u2019histoire d\\u2019Alsace et, plus largement de la vall\\u00e9e du Rhin. <br>Elle s\\u2019inscrit \\u00e9galement dans l\\u2019histoire de l\\u2019Europe, entre France et Allemagne, royaumes, empires ou r\\u00e9publiques.<\\/p>\\n<div><\\/div>\\n<div><\\/div>"},"elements":[],"widgetType":"text-editor"}],"isInner":false}],"isInner":false},{"id":"bec67fd","elType":"section","settings":{"content_width":{"unit":"px","size":892},"background_background":"classic","structure":"22","background_hover_background":"gradient","background_hover_color":"#f6f0e5","background_hover_color_b":"#e1c1a1"},"elements":[{"id":"a076978","elType":"column","settings":{"_column_size":66,"content_position":"center","animation":"fadeInUp","background_background":"classic","_inline_size":null,"background_hover_background":"classic"},"elements":[{"id":"e16a0b7","elType":"widget","settings":{"wp":{"title":"A LA UNE","number":"1","show_date":"on"},"_margin":{"unit":"px","top":"0","right":"0","bottom":"0","left":"0","isLinked":true},"_padding":{"unit":"px","top":"28"