ound_background":"classic","background_hover_color":"#f6f0e5","background_hover_color_b":"#e1c1a1"},"elements":[{"id":"40781d8","elType":"column","settings":{"_column_size":100},"elements":[{"id":"7adcad0","elType":"widget","settings":{"title":"Strasbourg...","align":"center","title_color":"#e1c1a1","typography_typography":"custom","typography_font_family":"Merienda One"},"elements":[],"widgetType":"heading"},{"id":"1ef318d","elType":"widget","settings":{"editor":"<p style=\\"text-align: left; font-family: Aref Ruqaa; padding-left: 30px;\\">\\u00c0 partir de 496, les Francs, ma\\u00eetres de l\\u2019Alsace, font surgir une nouvelle ville, Strateburgum (\\u00ab\\u00a0ville forte des routes\\u00a0\\u00bb).<\\/p><p style=\\"text-align: left; font-family: Aref Ruqaa; padding-left: 30px;\\">Fort modeste au d\\u00e9part, le bourg s\\u2019affirme sous le r\\u00e8gne des Carolingiens comme le carrefour des civilisations rh\\u00e9nanes.<\\/p><p style=\\"text-align: left; font-family: Aref Ruqaa; padding-left: 30px;\\">Strasbourg fut l\\u2019une des premi\\u00e8res villes \\u00e0 se d\\u00e9barrasser de la tutelle des \\u00e9v\\u00eaques, la bourgeoisie commer\\u00e7ante s\\u2019affirmant comme le vrai pouvoir.<br \\/> La construction de la cath\\u00e9drale ira de pair avec une prosp\\u00e9rit\\u00e9 grandissante.<br \\/> Le dynamisme \\u00e9conomique de la ville se double d''un bouillonnement intellectuel et culturel.<\\/p><p style=\\"text-align: left; font-family: Aref Ruqaa; padding-left: 30px;\\">Strasbourg, capitale de l\\u2019Europe et de l\\u2019Alsace, poss\\u00e8de un patrimoine historique et architectural qui en fait la ville la plus riche d\\u2019Alsace.<br \\/> Son centre ville fait partie du patrimoine mondial de L\\u2019UNESCO et ses mus\\u00e9es sont particuli\\u00e8rement riches et int\\u00e9ressants.<\\/p><p style=\\"text-align: left; font-family: Aref Ruqaa; padding-left: 30px;\\">L\\u2019histoire de la ville de Strasbourg est indissociable de l\\u2019histoire d\\u2019Alsace et, plus largement de la vall\\u00e9e du Rhin.<br \\/> Elle s\\u2019inscrit \\u00e9galement dans l\\u2019histoire de l\\u2019Europe, entre France et Allemagne, royaumes, empires ou r\\u00e9publiques.<\\/p>"},"elements":[],"widgetType":"text-editor"}],"isInner":false}],"isInner":false},{"id":"9b97d5f","elType":"section","settings":[],"elements":[{"id":"84165ca","elType":"column","settings":{"_column_size":100},"elements":[{"id":"d048664","elType":"widget","settings":[],"elements":[],"widgetType":"spacer"}],"isInner":false}],"isInner":false},{"id":"bec67fd","elType":"section","settings":{"content_width":{"unit":"px","size":892},"background_background":"classic","structure":"22","background_hover_background":"classic","background_hover_color_b":"#e1c1a1","background_hover_transition":{"unit":"px","size":0.6},"shape_divider_bottom":"mountains","shape_divider_bottom_color":"#f6f0e5","shape_divider_bottom_height":{"unit":"px","size":60}},"elements":[{"id":"a076978","elType":"column","settings":{"_column_size":66,"content_position":"center","animation":"fadeInUp","background_background":"classic","_inline_size":null,"background_hover_background":"classic","background_hover_color":"#f6f0e5"},"elements":[{"id":"e16a0b7","elType":"widget","settings":{"wp":{"title":"A LA UNE","number":"1","show_date":"on"},"_margin":{"unit":"px","top":"0","right":"0","bottom":"0","left":"0","isLinked":true},"_padding":{"unit":"px","top":"28","right":"28","bottom":"28","left":"28","isLinked":true},"_element_id":"recent_post","_background_hover_background":"gradient","_border_color":"#ffffff","_background_image":{"url":"http:\\/\\/strasbourg.sandrine-alcazar.com\\/wp-content\\/uploads\\/2018\\/03\\/830x532_led-horticoles-permettent-jeunes-poussent-grandir-tunnel-bunker-comestible-strasbourg-1.jpg","id":459},"_background_position":"center center","_background_repeat":"no-repeat","_background_size":"cover"},"elements":[],"widgetType":"wp-widget-recent-posts"}],"isInner":false},{"