(3242, 628, '_elementor_data', '[{"id":"a012bb2","elType":"section","settings":{"margin":{"unit":"px","top":"30","right":0,"bottom":"30","left":0,"isLinked":true}},"elements":[{"id":"7516828","elType":"column","settings":{"_column_size":100},"elements":[{"id":"03adcfe","elType":"widget","settings":{"title":"Visites et activit\\u00e9s dans la ville","align":"center","title_color":"#e1c1a1","typography_typography":"custom","typography_font_family":"Merienda One","_animation":"fadeInRight"},"elements":[],"widgetType":"heading"}],"isInner":false}],"isInner":false},{"id":"7a3b54f","elType":"section","settings":{"structure":"22","background_hover_background":"classic","background_hover_color":"#f6f0e5","animation":"fadeInLeft"},"elements":[{"id":"7e51c85","elType":"column","settings":{"_column_size":66,"_inline_size":null,"content_position":"center","background_hover_background":"classic","background_hover_color":"#f6f0e5","background_hover_transition":{"unit":"px","size":1}},"elements":[{"id":"f32c308","elType":"widget","settings":{"editor":"<h4 style=\\"text-align: center;\\"><span style=\\"font-size: 20px; color: #000000;\\"><strong>La Maison Kammerzell<\\/strong><\\/span><\\/h4><p style=\\"font-family: Aref Ruqaa;\\">Id\\u00e9alement situ\\u00e9 au pied de la Cath\\u00e9drale de Strasbourg, au c\\u0153ur de l\\u2019Europe, la c\\u00e9l\\u00e8bre Maison Kammerzell est un lieu incontournable \\u00e0 visiter.<\\/p><p style=\\"font-family: Aref Ruqaa;\\">Consid\\u00e9r\\u00e9e comme \\u00ab la plus belle maison de Strasbourg \\u00bb, elle symbolise des splendeurs s\\u00e9culaires de la ville qui en tire une grande fiert\\u00e9.<\\/p><p style=\\"font-family: Aref Ruqaa;\\">Elle est l\\u2019une des plus belles brasseries du monde et vous propose ce dimanche 15 avril \\u00e0 9h45 une visite guid\\u00e9e afin de d\\u00e9couvrir tous les d\\u00e9tails de sa construction et son histoire.<\\/p>","drop_cap":"yes","align_mobile":"justify","text_color":"#54595f","typography_typogra