INSERT INTO `dHFxxposts` (`ID`, `post_author`, `post_date`, `post_date_gmt`, `post_content`, `post_title`, `post_excerpt`, `post_status`, `comment_status`, `ping_status`, `post_password`, `post_name`, `to_ping`, `pinged`, `post_modified`, `post_modified_gmt`, `post_content_filtered`, `post_parent`, `guid`, `menu_order`, `post_type`, `post_mime_type`, `comment_count`) VALUES
(540, 1, '2018-03-26 12:51:32', '2018-03-26 12:51:32', '<h2>Bienvenue sur le site d''information de la ville </h2>		\n			<a href="http://strasbourg.sandrine-alcazar.com/actualites">\n			</a>\n		<h4 style="font-size: 20px; text-align: center;">ACTUALITÉS</h4><p>Vous pouvez retrouver dans cette page toutes les news en temps réel afin d''être informé de tout ce qui se passe à Strasbourg.</p>		\n			<a href="http://strasbourg.sandrine-alcazar.com/plus-dinfos">\n			</a>\n		<h4 style="font-size: 20px; text-align: center;">PLUS<i> </i>D''INFOS</h4><p>Cette page, elle, vous conseille quelques activités pour vous donner des idées lors de vos prochaines excursions dans la ville.</p>		\n			<a href="http://strasbourg.sandrine-alcazar.com/activites-du-mois">\n			</a>\n		<h4 style="font-size: 20px; text-align: center;">ACTIVITES DU MOIS</h4><p>Dans celle-ci, nous avons listé pour vous tous les évènements du mois de façon à ce que vous puissiez prévoir à l''avance vos sorties.</p>		\n			<a href="http://strasbourg.sandrine-alcazar.com/contact">\n			</a>\n		<h4 style="font-size: 20px; text-align: center;">CONTACT</h4>Et si vous avez quand même besoin de plus d''informations, vous pouvez remplir le formulaire se trouvant sur cette page, nous vous répondrons dans les meilleurs délais.		\n			<h2>Strasbourg...</h2>		\n		<p style="text-align: left; font-family: Aref Ruqaa; padding-left: 30px;">À partir de 496, les Francs, maîtres de l’Alsace, font surgir une nouvelle ville, Strateburgum (« ville forte des routes »).</p><p style="text-align: left; font-family: Aref Ruqaa; padding-left: 30px;">Fort modeste au départ, le bourg s’affirme sous le règne des Carolingiens comme le carrefour des civilisations rhénanes.</p><p style="text-align: left; font-family: Aref Ruqaa; padding-left: 30px;">Strasbourg fut l’une des premières villes à se débarrasser de la tutelle des évêques, la bourgeoisie commerçante s’affirmant comme le vrai pouvoir.<br /> La construction de la cathédrale ira de pair avec une prospérité grandissante.<br /> Le dynamisme économique de la ville se double d''un bouillonnement intellectuel et culturel.</p><p style="text-align: left; font-family: Aref Ruqaa; padding-left: 30px;">Strasbourg, capitale de l’Europe et de l’Alsace, possède un patrimoine historique et architectural qui en fait la ville la plus riche d’Alsace.<br /> Son centre ville fait partie du patrimoine mondial de L’UNESCO et ses musées sont particulièrement riches et intéressants.</p><p style="text-align: left; font-family: Aref Ruqaa; padding-left: 30px;">L’histoire de la ville de Strasbourg est indissociable de l’histoire d’Alsace et, plus largement de la vallée du Rhin.<br /> Elle s’inscrit également dans l’histoire de l’Europe, entre France et Allemagne, royaumes, empires ou républiques.</p>		\n						<a href="http://strasbourg.sandrine-alcazar.com/strasbourg-le-bunker-comestible-ferme-urbaine-souterraine-seme-ses-graines-en-france" data-elementor-open-lightbox="default">\n		<img width="300" height="192" src="http://strasbourg.sandrine-alcazar.com/wp-content/uploads/2018/03/830x532_led-horticoles-permettent-jeunes-poussent-grandir-tunnel-bunker-comestible-strasbourg-300x192.jpg" alt="" srcset="http://strasbourg.sandrine-alcazar.com/wp-content/uploads/2018/03/830x532_led-horticoles-permettent-jeunes-poussent-grandir-tunnel-bunker-comestible-strasbourg-300x192.jpg 300w, http://strasbourg.sandrine-alcazar.com/wp-content/uploads/2018/03/830x532_led-horticoles-permettent-jeunes-poussent-grandir-tunnel-bunker-comestible-strasbourg-768x492.jpg 768w, http://strasbourg.sandrine-alcazar.com/wp-content/uploads/2018/03/830x532_led-horticoles-permettent-jeunes-poussent-grandir-tunnel-bunker-comestible-strasbourg.jpg 830w" sizes="(max-width: 300px) 100vw, 300px" />				</a>', 'Accueil', '', 'inherit', 'closed', 'closed', '', '8-revision-v1', '', '', '2018-03-26 12:51:32', '2018-03-26 12:51:32', '', 8, 'http://strasbourg.sandrine-alcazar.com/8-revision-v1', 0, 'revision', '', 0),
