INSERT INTO `dHFxxposts` (`ID`, `post_author`, `post_date`, `post_date_gmt`, `post_content`, `post_title`, `post_excerpt`, `post_status`, `comment_status`, `ping_status`, `post_password`, `post_name`, `to_ping`, `pinged`, `post_modified`, `post_modified_gmt`, `post_content_filtered`, `post_parent`, `guid`, `menu_order`, `post_type`, `post_mime_type`, `comment_count`) VALUES
(94, 1, '2018-03-16 17:40:44', '2018-03-16 17:40:44', '[["DATES","TITRE","DESCRIPTION","RESERVATION"],["03\\/04\\/2018 au 08\\/04\\/2018 ","Journ\\u00e9es europ\\u00e9ennes des m\\u00e9tiers d''art ","Les Journ\\u00e9es Europ\\u00e9ennes des M\\u00e9tiers d''Art sont la plus grande manifestation internationale d\\u00e9di\\u00e9e \\u00e0 la d\\u00e9couverte des m\\u00e9tiers d\\u2019art, un secteur remarquable par sa diversit\\u00e9 et sa vitalit\\u00e9, \\u00e0 la crois\\u00e9e de la culture, de l''\\u00e9conomie, du patrimoine et de la cr\\u00e9ation.","<a href=\\"[ninja_form id=8]\\" target=\\"blank\\">Inscription<\\/a>"],["04\\/04\\/2018","Les Shadoks ont 50 ans : Une r\\u00e9volution anim\\u00e9e ","En partenariat avec le Shadok, Fabrique du Num\\u00e9rique et aaa production, le Mus\\u00e9e Tomi Ungerer \\u2013 Centre international de l\\u2019Illustration propose de d\\u00e9couvrir ou de red\\u00e9couvrir la fameuse s\\u00e9rie t\\u00e9l\\u00e9vis\\u00e9e de films d\\u2019animation cr\\u00e9\\u00e9e en 1968 par Jacques Rouxel (1931-2004). Pour la premi\\u00e8re fois l\\u2019oeuvre du cr\\u00e9ateur est expos\\u00e9e dans un mus\\u00e9e labellis\\u00e9 \\u00ab Mus\\u00e9e de France \\u00bb avec l\\u2019objectif de l\\u2019inscrire dans l\\u2019histoire de l\\u2019illustration du XXe si\\u00e8cle. ","[su_button url=\\"[ninja_form_id=8]\\" target=\\"blank\\"]Button text[\\/su_button]"],["05\\/04\\/2018","EDUCAP CITY","Parcours d\\u2019orientation en milieu urbain encadr\\u00e9 par le Centre de Loisirs Jeunes de la police Nationale.","[wpi_designer_button id=397]"],["10\\/04\\/2018","Kvelertak","Form\\u00e9 en 2007 KVELERTAK conna\\u00eet une ascension rapide et incarne un des meilleurs repr\\u00e9sentants du metal des ann\\u00e9es 2010 : syncr\\u00e9tique, d\\u00e9complex\\u00e9 et taill\\u00e9 pour le live. \\nA l''image de Baroness, les Norv\\u00e9giens ont ramen\\u00e9 une grosse touche fun et heavy dans un univers dark, celui du black metal.\\nLe groupe fait \\u00e9tape \\u00e0 La Laiterie pendant leur tourn\\u00e9e avec Metallica.","[wpi_designer_button id=397]"],["11\\/04\\/2018 ","Conf\\u00e9rence: Femmes guerri\\u00e8res du Dahomey","Ces femmes ont servi le r\\u00e9gime avec une abn\\u00e9gation sans faille. Redout\\u00e9es par tous ceux qui les ont affront\\u00e9es au combat, elles ont marqu\\u00e9 les esprits, non seulement au Dahomey mais dans toute l''Afrique.","[wpi_designer_button id=397]"],["13\\/04\\/2018 au 15\\/04\\/2018 ","Les courses de Strasbourg","V\\u00e9ritable festival du sport pour tous en Alsace, les Courses de Strasbourg Europe rassemblent chaque ann\\u00e9e plus de 13 000 participants sur 6 \\u00e9preuves, faisant ainsi de ce rendez-vous populaire la plus grande course de la R\\u00e9gion Grand Est et l\\u2019une des plus importantes de France.\\n\\nVous pouvez retrouvez toutes les informations sur le site de l''Association Courses de Strasbourg Europe.","[wpi_designer_button id=397]"],["13\\/04\\/2018 au 20\\/04\\/2018","Dr\\u00f4les de Z\\u00e8bres","Dr\\u00f4les de Z\\u00e8bres est un festival d''humour \\u00e0 Strasbourg qui r\\u00e9unit de jeunes humoristes et des artistes confirm\\u00e9s de toutes les origines.","[wpi_designer_button id=397]"],["18\\/04\\/2018","Marcus Miller","Marcus Miller revient sur sc\\u00e8ne \\u00e0 l\\u2019auditorium Erasme avec un nouvel album pour notre plus grand plaisir.","[wpi_designer_button id=397]"],["20\\/04\\/2018","Big Flo et Oli","Apr\\u00e8s une tourn\\u00e9e \\u00e0 guichets ferm\\u00e9s \\u00e0 l\\u2019automne 2017, les deux toulousains partent \\u00e0 la conqu\\u00eate des Z\\u00e9niths ! Une nouvelle tourn\\u00e9e d\\u2019une dizaine de dates \\u00e0 travers la France, mais \\u00e9galement en Belgique et en Suisse.","[wpi_designer_button id=397]"],["21\\/04\\/2018","Atelier de dessins ","Atelier de dessin avec Batiste Filippi, illustrateur, le 21 avril 2018","[wpi_designer_button id=397]"],["22\\/04\\/2018 ","Salon du tissu Edition Printemps\\/Et\\u00e9","Sur plus de 4000 m\\u00e8tres carr\\u00e9s, vous trouverez :\\ntissus pour la conception de v\\u00eatements, pour robe de mari\\u00e9e, pour la haute couture, pour enfants, pour le patchwork ou la d\\u00e9coration, d''ameublement mais aussi du cuir, des toiles cir\\u00e9es, et tout le n\\u00e9cessaire de mercerie.","[wpi_designer_button id=397]"],["23\\/04\\/2018 au 27\\/04\\/2018","Stage kayak\\/escalade \\u00e0 l\\u2019ASCPA","L\\u2019ASCPA organise un stage kayak\\/escalade de 5 jours pour les jeunes de 7 \\u00e0 17 ans durant les vacances de Printemps 2018.","[wpi_designer_button id=397]"],["27\\/04\\/2018 au 28\\/04\\/2018 ","R\\u00e9volution Cubaine ","Une soir\\u00e9e Salsa dans la peau d''un r\\u00e9volutionnaire ?\\nVotre r\\u00eave le plus fou va enfin devenir r\\u00e9alit\\u00e9 !\\n\\nDevenez un r\\u00e9volutionnaire dans le maquis, cigare aux l\\u00e8vres\\nApr\\u00e8s la soir\\u00e9e Carnaval, rien de mieux que la rigueur de la lutte r\\u00e9volutionnaire pour imposer la Salsa partout dans le monde.","[wpi_designer_button id=397]"],["28\\/04\\/2018","Strasbourg - Nice","Les alsaciens du Racing Club de Strasbourg affrontent, au Stade de la Meinau, les joueurs de l''OGC Nice (battus 2-1 au match aller au stade Allianz Riviera en octobre 2017), dans le cadre de la 35\\u00e8me journ\\u00e9e de la Ligue 1 2017-2018.","[wpi_designer_button id=397]"],["28\\/04\\/2018 au 01\\/05\\/2018 ","SALON AUTO-MOTO CLASSIC","La 1\\u00e8re \\u00e9dition du nouveau grand rendez-vous d\\u00e9di\\u00e9 aux v\\u00e9hicules d\\u2019\\u00e9poque !\\n\\nPr\\u00e9sentant plus de 150 exposants sur 25 000 m\\u00b2 d\\u2019exposition durant 4 jours, il est organis\\u00e9 avec le concours de l\\u2019Automobile Club Association.","[wpi_designer_button id=397]"]]', 'Événements  à venir', '', 'publish', 'closed', 'closed', '', 'activites-a-venir', '', '', '2018-04-03 15:10:59', '2018-04-03 15:10:59', '', 0, 'http://strasbourg.sandrine-alcazar.com/?post_type=tablepress_table&#038;p=94', 0, 'tablepress_table', 'application/json', 0),
(95, 1, '2018-03-16 17:41:39', '2018-03-16 17:41:39', '[["DATES","TITRE","DESCRIPTION"],["03\\/04\\/2018 au 08\\/04\\/2018 ","Journ\\u00e9es europ\\u00e9ennes des m\\u00e9tiers d''art ","Les Journ\\u00e9es Europ\\u00e9ennes des M\\u00e9tiers d''Art sont la plus grande manifestation internationale d\\u00e9di\\u00e9e \\u00e0 la d\\u00e9couverte des m\\u00e9tiers d\\u2019art, un secteur remarquable par sa diversit\\u00e9 et sa vitalit\\u00e9, \\u00e0 la crois\\u00e9e de la culture, de l''\\u00e9conomie, du patrimoine et de la cr\\u00e9ation."],["04\\/04\\/2018","Les Shadoks ont 50 ans : Une r\\u00e9volution anim\\u00e9e ","En partenariat avec le Shadok, Fabrique du Num\\u00e9rique et aaa production, le Mus\\u00e9e Tomi Ungerer \\u2013 Centre international de l\\u2019Illustration propose de d\\u00e9couvrir ou de red\\u00e9couvrir la fameuse s\\u00e9rie t\\u00e9l\\u00e9vis\\u00e9e de films d\\u2019animation cr\\u00e9\\u00e9e en 1968 par Jacques Rouxel (1931-2004). Pour la premi\\u00e8re fois l\\u2019oeuvre du cr\\u00e9ateur est expos\\u00e9e dans un mus\\u00e9e labellis\\u00e9 \\u00ab Mus\\u00e9e de France \\u00bb avec l\\u2019objectif de l\\u2019inscrire dans l\\u2019histoire de l\\u2019illustration du XXe si\\u00e8cle. "],["05\\/04\\/2018","EDUCAP CITY","Parcours d\\u2019orientation en milieu urbain encadr\\u00e9 par le Centre de Loisirs Jeunes de la police Nationale."],["10\\/04\\/2018","Kvelertak","Form\\u00e9 en 2007 KVELERTAK conna\\u00eet une ascension rapide et incarne un des meilleurs repr\\u00e9sentants du metal des ann\\u00e9es 2010 : syncr\\u00e9tique, d\\u00e9complex\\u00e9 et taill\\u00e9 pour le live. \\nA l''image de Baroness, les Norv\\u00e9giens ont ramen\\u00e9 une grosse touche fun et heavy dans un univers dark, celui du black metal.\\nLe groupe fait \\u00e9tape \\u00e0 La Laiterie pendant leur tourn\\u00e9e avec Metallica."],["11\\/04\\/2018 ","Conf\\u00e9rence: Femmes guerri\\u00e8res du Dahomey","Ces femmes ont servi le r\\u00e9gime avec une abn\\u00e9gation sans faille. Redout\\u00e9es par tous ceux qui les ont affront\\u00e9es au combat, elles ont marqu\\u00e9 les esprits, non seulement au Dahomey mais dans toute l''Afrique."],["13\\/04\\/2018 au 15\\/04\\/2018 ","Les courses de Strasbourg","V\\u00e9ritable festival du sport pour tous en Alsace, les Courses de Strasbourg Europe rassemblent chaque ann\\u00e9e plus de 13 000 participants sur 6 \\u00e9preuves, faisant ainsi de ce rendez-vous populaire la plus grande course de la R\\u00e9gion Grand Est et l\\u2019une des plus importantes de France.\\n\\nVous pouvez retrouvez toutes les informations sur le site de l''Association Courses de Strasbourg Europe."],["13\\/04\\/2018 au 20\\/04\\/2018","Dr\\u00f4les de Z\\u00e8bres","Dr\\u00f4les de Z\\u00e8bres est un festival d''humour \\u00e0 Strasbourg qui r\\u00e9unit de jeunes humoristes et des artistes confirm\\u00e9s de toutes les origines."],["18\\/04\\/2018","Marcus Miller","Marcus Miller revient sur sc\\u00e8ne \\u00e0 l\\u2019auditorium Erasme avec un nouvel album pour notre plus grand plaisir."],["20\\/04\\/2018","Big Flo et Oli","Apr\\u00e8s une tourn\\u00e9e \\u00e0 guichets ferm\\u00e9s \\u00e0 l\\u2019automne 2017, les deux toulousains partent \\u00e0 la conqu\\u00eate des Z\\u00e9niths ! Une nouvelle tourn\\u00e9e d\\u2019une dizaine de dates \\u00e0 travers la France, mais \\u00e9galement en Belgique et en Suisse."],["21\\/04\\/2018","Atelier de dessins ","Atelier de dessin avec Batiste Filippi, illustrateur, le 21 avril 2018"],["22\\/04\\/2018 ","Salon du tissu Edition Printemps\\/Et\\u00e9","Sur plus de 4000 m\\u00e8tres carr\\u00e9s, vous trouverez :\\ntissus pour la conception de v\\u00eatements, pour robe de mari\\u00e9e, pour la haute couture, pour enfants, pour le patchwork ou la d\\u00e9coration, d''ameublement mais aussi du cuir, des toiles cir\\u00e9es, et tout le n\\u00e9cessaire de mercerie."],["23\\/04\\/2018 au 27\\/04\\/2018","Stage kayak\\/escalade \\u00e0 l\\u2019ASCPA","L\\u2019ASCPA organise un stage kayak\\/escalade de 5 jours pour les jeunes de 7 \\u00e0 17 ans durant les vacances de Printemps 2018."],["27\\/04\\/2018 au 28\\/04\\/2018 ","R\\u00e9volution Cubaine ","Une soir\\u00e9e Salsa dans la peau d''un r\\u00e9volutionnaire ?\\nVotre r\\u00eave le plus fou va enfin devenir r\\u00e9alit\\u00e9 !\\n\\nDevenez un r\\u00e9volutionnaire dans le maquis, cigare aux l\\u00e8vres\\nApr\\u00e8s la soir\\u00e9e Carnaval, rien de mieux que la rigueur de la lutte r\\u00e9volutionnaire pour imposer la Salsa partout dans le monde."],["28\\/04\\/2018","Strasbourg - Nice","Les alsaciens du Racing Club de Strasbourg affrontent, au Stade de la Meinau, les joueurs de l''OGC Nice (battus 2-1 au match aller au stade Allianz Riviera en octobre 2017), dans le cadre de la 35\\u00e8me journ\\u00e9e de la Ligue 1 2017-2018."],["28\\/04\\/2018 au 01\\/05\\/2018 ","SALON AUTO-MOTO CLASSIC","La 1\\u00e8re \\u00e9dition du nouveau grand rendez-vous d\\u00e9di\\u00e9 aux v\\u00e9hicules d\\u2019\\u00e9poque !\\n\\nPr\\u00e9sentant plus de 150 exposants sur 25 000 m\\u00b2 d\\u2019exposition durant 4 jours, il est organis\\u00e9 avec le concours de l\\u2019Automobile Club Association."]]', 'Activités à venir', '', 'inherit', 'closed', 'closed', '', '94-revision-v1', '', '', '2018-03-16 17:41:39', '2018-03-16 17:41:39', '', 94, 'http://strasbourg.sandrine-alcazar.com/94-revision-v1', 0, 'revision', '', 0),
