isplay:flex;\n	width:100%;\n	font-weight:bold;\n	font-size:18px;\n	color:rgb(233, 30, 99);\n	\n}\n\n.events-table .event-description {\n	width:100%;	\n	margin-top:20px;\n}\n\n.events-table .event-reservation {\n	display:flex;\n	width:100%;\n	text-align:center;\n	margin-bottom:40px;\n	margin-top:10px;\n	\n}\n\n.events-table .event-reservation a {\n	width:180px;\n	height:60px;\n	margin:0;\n	align-self:center;\n	padding-top:15px;\n  font-size:18px;\n}\n\n.em-pagination {\n	text-align:center;\n	margin-top:20px;\n}\n\n}\n\n\n', 'Strasbourg', '', 'publish', 'closed', 'closed', '', 'strasbourg', '', '', '2018-04-07 07:22:48', '2018-04-07 07:22:48', '', 0, 'http://strasbourg.sandrine-alcazar.com/strasbourg', 0, 'custom_css', '', 0),
