\n}\n\n#nf-drawer-content {\n	font-size:12px\n}\n \n.contact_button_wrapper {\n	text-align:center;\n}\n\n/*FOOTER*/\n\n.col-md-4 {\n	text-align:center\n}\n\n#a2a_follow_widget-3 {\n	text-align:center;\n}\n\n\n', 'Strasbourg', '', 'inherit', 'closed', 'closed', '', '131-revision-v1', '', '', '2018-03-26 19:37:08', '2018-03-26 19:37:08', '', 131, 'http://strasbourg.sandrine-alcazar.com/131-revision-v1', 0, 'revision', '', 0),
