(675, 1, '2018-03-28 11:09:47', '2018-03-28 11:09:47', '<h2>Agenda des événements à venir</h2>\r\n\r\nTrouvez ici une liste de tout ce qui sur la région alsacienne pendant le mois en cours.\r\n[table id=Activites_mensuelles /]\r\n', 'Activités du mois', '', 'inherit', 'closed', 'closed', '', '88-revision-v1', '', '', '2018-03-28 11:09:47', '2018-03-28 11:09:47', '', 88, 'http://strasbourg.sandrine-alcazar.com/88-revision-v1', 0, 'revision', '', 0),
