able .event-description {\n	width:45%;\n	vertical-align:top;\n}\n\n.events-table .event-description p {\n	font-size:15px;\n}\n\n\n.events-table .event-reservation {\n	width:20%;\n	text-align:center;\n}\n\n.events-table .event-reservation a {\n	background-color:#E1C1A1;\n	border: 1px solid #FEF5D6;\n	padding:3px 10px 5px 10px;\n	border-radius:5px;\n	box-shadow:#E1C1A1 0px 14px 26px -12px;\n	color: white;\n	font-weight:bold;\n	text-transform:uppercase;\n}\n\n.events-table .event-reservation a:hover {\n	box-shadow:rgb(233, 30, 99) 0px 14px 26px -12px;\n	background-color:rgb(233, 30, 99);\n	color:white;\n}\n\n.em-pagination {\n	text-align:center;\n	font-size:16px;\n	margin-bottom:20px;\n}\n\n.em-pagination .page-numbers {\n	text-align:center;\n	vertical-align:middle;\n	background-color:#E1C1A1;\n	padding:0 9px 6px 9px;\n	margin:2px;\n	border-radius:100%;\n  box-shadow:#E1C1A1 0px 20px      30px -12px;\n	cursor:pointer;\n}\n\n.em-pagination .page-numbers:hover {\n	box-shadow:rgb(233, 30, 99) 0px 20px 30px -12px;\n	background-color:rgb(233, 30, 99);\n	color:white;\n}\n\n\n}\n\n\n', 'Strasbourg', '', 'inherit', 'closed', 'closed', '', '131-revision-v1', '', '', '2018-04-05 09:13:41', '2018-04-05 09:13:41', '', 131, 'http://strasbourg.sandrine-alcazar.com/131-revision-v1', 0, 'revision', '', 0),
