rder-radius:100%;\n  box-shadow:#E1C1A1 0px 20px      30px -12px;\n	cursor:pointer;\n}\n\n.em-pagination .page-numbers:hover {\n	box-shadow:rgb(233, 30, 99) 0px 20px 30px -12px;\n	background-color:rgb(233, 30, 99);\n	color:white;\n}\n\n\n/*Evenement*/\n\n.elementor-element-487d643d {\n	border-radius:10px;\n}\n\n#nf-form-title-8 {\n	text-align: center;\n	color:#E1C1A1;\n	font-size:40px;\n	text-shadow: #FFF 1px 1px, #000 	-1px 1px, #000 -1px -1px, #000 	 1px -1px;\n}\n\n.nf-form-wrap {\n	font-family:Aref Ruqaa;\n}\n\n#nf-field-104-container {\n	text-align:center;\n}\n\n/*CONTACT*/\n\n#nf-form-title-2 {\n	text-align: center;\n	color:#E1C1A1;\n	font-size:40px;\n	text-shadow: #FFF 1px 1px, #000 	-1px 1px, #000 -1px -1px, #000 	 1px -1px;\n}\n\n.nf-before-form-content {\n	font-size:12px;\n	margin-bottom:30px;\n}\n\n.divider_wrapper {\n	padding-bottom:20px;\n	padding-top:20px;\n}\n\nlabel {\n	text-align:center;\n}\n\n.nf-field-element {\n	padding-right:30px;\n}\n\n#nf-drawer-content {\n	font-size:12px\n}\n \n.contact_button_wrapper {\n	text-align:center;\n}\n\n/*FOOTER*/\n\n.col-md-4 {\n	text-align:center\n}\n\n#a2a_follow_widget-3 {\n	text-align:center;\n}\n\n.copyright.pull-right {\n    display:none;\n}\n\n@media screen and (max-width:640px) {\n	/*ACTIVITES DU MOIS*/\n\n.css-events-list {\n	display:flex;\n	flex-direction:column;\n  \n}\n\n\n.events-table {\n	border:none;\n}\n\n.events-table tr {\n	border:none;\n}\n\n\n\n.events-table thead {\n		display:flex;\n	}\n\n.events-table th {\n\n\n\n\n}\n\n#event-time header {\n	\n}\n	\n.events-table td {\n		display:flex;\n	flex-direction:column;\n	justify-content:center;\n		background-color:pink;\n	}\n\n.events-table .event-time{\n	display:flex;\n	width:100%;\n	margin-top:60px;\n}\n\n.events-table .event-title  {\n	width:100%;\n	margin-top:20px;\n}\n\n.events-table .event-description {\n	width:100%;	\n	margin-top:20px;\n}\n\n.events-table .event-reservation {\n	display:flex;\n	width:100%;\n	margin-top:20px;\n	text-align:center;\n}\n\n.events-table .event-reservation a {\n	margin:0;\n	align-self:center;\n	width:110px;\n}\n\n.events-table .event-reservation a:hover {\n	box-shadow:rgb(233, 30, 99) 0px 14px 26px -12px;\n	background-color:rgb(233, 30, 99);\n	color:white;\n}\n\n.em-pagination {\n	text-align:center;\n	font-size:16px;\n	margin-bottom:20px;\n}\n\n.em-pagination .page-numbers {\n	text-align:center;\n	vertical-align:middle;\n	background-color:#E1C1A1;\n	padding:0 9px 6px 9px;\n	margin:2px;\n	border-radius:100%;\n  box-shadow:#E1C1A1 0px 20px      30px -12px;\n	cursor:pointer;\n}\n\n.em-pagination .page-numbers:hover {\n	box-shadow:rgb(233, 30, 99) 0px 20px 30px -12px;\n	background-color:rgb(233, 30, 99);\n	color:white;\n}\n\n\n}\n\n\n', 'Strasbourg', '', 'inherit', 'closed', 'closed', '', '131-revision-v1', '', '', '2018-04-05 09:49:15', '2018-04-05 09:49:15', '', 131, 'http://strasbourg.sandrine-alcazar.com/131-revision-v1', 0, 'revision', '', 0),
