.events-table .event-reservation {\n	display:flex;\n	width:100%;\n	text-align:center;\n	margin-bottom:40px;\n	margin-top:10px;\n}\n\n.events-table .event-reservation a {\n	margin:0;\n	align-self:center;\n	width:110px;\n}\n\n.events-table .event-reservation a:hover {\n	box-shadow:rgb(233, 30, 99) 0px 14px 26px -12px;\n	background-color:rgb(233, 30, 99);\n	color:white;\n}\n\n.em-pagination {\n	text-align:center;\n	font-size:16px;\n	margin-bottom:20px;\n}\n\n.em-pagination .page-numbers {\n	text-align:center;\n	vertical-align:middle;\n	background-color:#E1C1A1;\n	padding:0 9px 6px 9px;\n	margin:2px;\n	border-radius:100%;\n  box-shadow:#E1C1A1 0px 20px      30px -12px;\n	cursor:pointer;\n}\n\n.em-pagination .page-numbers:hover {\n	box-shadow:rgb(233, 30, 99) 0px 20px 30px -12px;\n	background-color:rgb(233, 30, 99);\n	color:white;\n}\n\n\n}\n\n\n', 'Strasbourg', '', 'inherit', 'closed', 'closed', '', '131-revision-v1', '', '', '2018-04-05 10:07:53', '2018-04-05 10:07:53', '', 131, 'http://strasbourg.sandrine-alcazar.com/131-revision-v1', 0, 'revision', '', 0);
