e:18px;\n	color:rgb(233, 30, 99);\n	\n}\n\n.events-table .event-description {\n	width:100%;	\n	margin-top:20px;\n}\n\n.events-table .event-reservation {\n	display:flex;\n	width:100%;\n	text-align:center;\n	margin-bottom:40px;\n	margin-top:10px;\n	\n}\n\n.events-table .event-reservation a {\n	width:180px;\n	height:60px;\n	margin:0;\n	align-self:center;\n	padding-top:15px;\n  font-size:18px;\n}\n\n.em-pagination {\n	text-align:center;\n	margin-top:20px;\n}\n\n}\n\n\n', 'Strasbourg', '', 'inherit', 'closed', 'closed', '', '131-revision-v1', '', '', '2018-04-06 08:55:16', '2018-04-06 08:55:16', '', 131, 'http://strasbourg.sandrine-alcazar.com/131-revision-v1', 0, 'revision', '', 0),
